import{_ as t,o as s,c as i,a2 as a}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install.md","filePath":"guide/install.md"}'),o={name:"guide/install.md"};function n(r,e,l,d,c,h){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>callytics is meant to run on a Linux host with Docker. The default stack starts six containers: Asterisk, Stasis, NestJS API, PostgreSQL, Redis, and the React frontend.</p><h2 id="supported-environments" tabindex="-1">Supported environments <a class="header-anchor" href="#supported-environments" aria-label="Permalink to &quot;Supported environments&quot;">​</a></h2><ul><li>Ubuntu 22.04 and 24.04 are tested and supported.</li><li>Linux only.</li><li>Docker 24 or newer.</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Linux host.</li><li>Docker Compose v2.</li><li>Ports <code>80</code>, <code>443</code>, <code>5080</code> over UDP and TCP, <code>8088</code>, <code>3000</code>, and <code>3001</code> must be free.</li><li>If you plan to use remote SIP phones through WireGuard, keep UDP port <code>51820</code> free as well.</li></ul><h2 id="run-the-install-script" tabindex="-1">Run the install script <a class="header-anchor" href="#run-the-install-script" aria-label="Permalink to &quot;Run the install script&quot;">​</a></h2><p>Clone the repository, create your environment file, then run the install script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/rayanweragala/callytics.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> callytics</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/install.sh</span></span></code></pre></div><h2 id="required-configuration-before-first-start" tabindex="-1">Required configuration before first start <a class="header-anchor" href="#required-configuration-before-first-start" aria-label="Permalink to &quot;Required configuration before first start&quot;">​</a></h2><p>Before running <code>bash scripts/install.sh</code>, copy <code>.env.example</code> to <code>.env</code> and set these values:</p><ul><li><code>HOST_IP</code> - set to your machine&#39;s LAN IP address, not <code>127.0.0.1</code>. Run <code>ip route get 1 | awk &#39;{print $7; exit}&#39;</code> to find it. Leaving it as <code>127.0.0.1</code> means softphones on other devices will fail to register and SIP QR codes will be wrong.</li><li><code>RECORDINGS_INTERNAL_TOKEN</code> - change from the default value. Used to authenticate internal recording requests between Stasis and backend.</li><li><code>SIP_PORT</code> - default <code>5080</code>. Only change if that port is already in use on your host.</li></ul><p>For manual install flow internals and recovery/reference steps, see <code>docs/install-flow.md</code>.</p><p>The first boot is slower than later restarts. The Asterisk image builds from source inside the container and usually takes 3-5 minutes on a small VPS. PostgreSQL starts with the <code>callytics</code> database, backend migrations run automatically, and the frontend is served on <code>http://localhost:3000</code>.</p><h2 id="what-s-running" tabindex="-1">What&#39;s Running <a class="header-anchor" href="#what-s-running" aria-label="Permalink to &quot;What&#39;s Running&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th style="text-align:right;">Port</th><th>Purpose</th></tr></thead><tbody><tr><td><code>postgres</code></td><td style="text-align:right;"><code>5432</code> bound to <code>127.0.0.1</code></td><td>Stores flows, extensions, trunks, inbound routes, call logs, firewall records, and backup metadata.</td></tr><tr><td><code>redis</code></td><td style="text-align:right;"><code>6380</code> on the host, <code>6379</code> in the container</td><td>Carries live call telemetry, queue state, operator state, SIP capture events, and short-lived runtime coordination.</td></tr><tr><td><code>asterisk</code></td><td style="text-align:right;"><code>5080</code> SIP, <code>8088</code> ARI, RTP from the Asterisk config</td><td>Handles SIP registration, trunks, media, ARI channels, bridges, recordings, and telephony config reloads.</td></tr><tr><td><code>backend</code></td><td style="text-align:right;"><code>3001</code></td><td>NestJS API for the dashboard, configuration writes, uploads, recordings, diagnostics, firewall, VPN, and backup operations.</td></tr><tr><td><code>frontend</code></td><td style="text-align:right;"><code>3000</code></td><td>React dashboard for IVR editing, operators, queues, campaigns, firewall, diagnostics, recordings, and configuration.</td></tr><tr><td><code>stasis</code></td><td style="text-align:right;">no public HTTP port</td><td>Node execution engine that receives ARI calls from Asterisk, loads the published flow, runs nodes, and emits Redis timeline events.</td></tr></tbody></table><h2 id="webrtc-softphone-support" tabindex="-1">WebRTC softphone support <a class="header-anchor" href="#webrtc-softphone-support" aria-label="Permalink to &quot;WebRTC softphone support&quot;">​</a></h2><p>The browser softphone does not require a separate app. It connects through Asterisk&#39;s WebSocket transport on port <code>8088</code>, which is now regenerated automatically during backend startup.</p><p>The backend also writes WebRTC-specific Asterisk settings automatically:</p><ul><li>WebSocket transport binds on port <code>8088</code></li><li>ICE support is enabled for WebRTC media negotiation</li><li>Docker bridge subnets are auto-discovered and written as <code>local_net</code> entries so RTP routing stays correct</li></ul><h2 id="audio-and-codec-notes" tabindex="-1">Audio and codec notes <a class="header-anchor" href="#audio-and-codec-notes" aria-label="Permalink to &quot;Audio and codec notes&quot;">​</a></h2><ul><li>Asterisk is built with Opus codec support through Sangoma <code>codec_opus</code>.</li><li>Audio files are stored as PCM WAV so Asterisk playback stays compatible across prompts and generated media.</li></ul><h2 id="first-boot-timeline" tabindex="-1">First Boot Timeline <a class="header-anchor" href="#first-boot-timeline" aria-label="Permalink to &quot;First Boot Timeline&quot;">​</a></h2><ol><li>Docker pulls the base images and service images needed by the stack.</li><li>The Asterisk container builds from source. This usually takes 3 to 5 minutes on a small VPS.</li><li>PostgreSQL initialises the <code>callytics</code> database.</li><li>NestJS starts and runs migrations automatically.</li><li>The frontend becomes available on port <code>3000</code>.</li><li>Stasis connects to Asterisk ARI on port <code>8088</code> and waits for calls.</li></ol><h2 id="optional-vpn-profile" tabindex="-1">Optional VPN Profile <a class="header-anchor" href="#optional-vpn-profile" aria-label="Permalink to &quot;Optional VPN Profile&quot;">​</a></h2><p>The WireGuard container is opt-in. Start it only when you need VPN peer provisioning for remote softphones:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vpn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Set <code>HOST_IP</code>, <code>VPN_PUBLIC_IP</code>, or <code>WIREGUARD_SERVERURL</code> in <code>.env</code> before generating peer configs if the server is behind NAT or has a public DNS name.</p><h2 id="verifying-the-installation" tabindex="-1">Verifying the installation <a class="header-anchor" href="#verifying-the-installation" aria-label="Permalink to &quot;Verifying the installation&quot;">​</a></h2><p>After the stack is up, run through these checks to confirm everything is working:</p><ol><li><p><strong>Dashboard loads</strong> — open <code>http://localhost:3000</code>. The React dashboard should load without errors.</p></li><li><p><strong>All services healthy</strong> — go to Diagnostics. The health panel should show <code>HEALTHY</code> for all six services: ARI, AMI, Asterisk, PostgreSQL, Redis, and uptime. If any service shows unhealthy, check its container logs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asterisk</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stasis</span></span></code></pre></div></li><li><p><strong>Softphone registers</strong> — configure a SIP client (Linphone, Zoiper, or any PJSIP-compatible softphone) with an extension credential. Set the server to <code>&lt;host-ip&gt;:5080</code>. After registration, go to Configure -&gt; Extensions — the extension status should show as registered.</p><p>The browser softphone is available inside the dashboard too. Open the phone bubble, select an operator, click <code>Connect</code>, and wait for <code>Registered</code>.</p></li><li><p><strong>Inbound call routes</strong> — go to Configure -&gt; Inbound, create an inbound route with a DID, assign a published flow, and dial the DID from the softphone. The call should execute the flow.</p></li></ol><p>If Diagnostics shows any service as unhealthy, <code>docker compose logs &lt;service-name&gt;</code> will show the relevant error output.</p>`,32)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
